insert into content_tips (id, course_id, unit_order, cefr_level, skill, type, topic, title, body, example) values
('a0dfa6d5-8520-5ad6-bca3-ad3ff773664e'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,7,'A2',$p$writing$p$,$p$gramatica$p$,$p$passado_perfeito$p$,$p$El pasado brasileño: «-ei, -i» para lo que YA hiciste$p$,$p$Para contar lo que hiciste, el pretérito perfeito cambia la terminación: -ar → «falei», -er → «comi», -ir → «abri». Ojo con los irregulares clave: ir/ser → «fui», fazer → «fiz», ter → «tive». «Ontem» (ayer) avisa de que toca este pasado.$p$,$p$Ontem eu falei com a Ana, comi pizza e fui ao cinema.$p$),
('f6f5099d-00b2-56cc-88a0-c83d8ae54ffd'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,8,'A2',$p$speaking$p$,$p$gramatica$p$,$p$futuro_ir$p$,$p$El futuro fácil: «vou» + infinitivo$p$,$p$En el día a día los brasileños casi no usan el futuro «-ei»; dicen «ir + infinitivo»: vou viajar, você vai estudar, nós vamos sair. Es el «voy a…» del español. Para «mañana», usa «amanhã».$p$,$p$Amanhã eu vou viajar para São Paulo e vou visitar a minha família.$p$),
('55ecda2c-36de-5834-b386-2fa9dcb95520'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,9,'A2',$p$reading$p$,$p$vocabulario$p$,$p$viagem$p$,$p$De viaje: se «pega» el autobús, no se «toma»$p$,$p$Para el transporte, en Brasil se «pega» el medio: pegar o ônibus, pegar o metrô, pegar um táxi. «A passagem» es el billete; «a rodoviária», la estación de autobuses; «o aeroporto», el aeropuerto.$p$,$p$Eu vou pegar o ônibus na rodoviária e comprar a passagem lá.$p$),
('bb2df50a-a5e2-5d5f-8af3-bd5649276bbd'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,10,'A2',$p$speaking$p$,$p$vocabulario$p$,$p$restaurante$p$,$p$En el restaurante: «a conta, por favor»$p$,$p$Para pedir, «Eu vou querer…» suena natural. El camarero es «o garçom»; la cuenta, «a conta»; la propina, «a gorjeta» (el 10% suele venir ya en la cuenta). «Está incluído?» pregunta si va incluido.$p$,$p$Garçom, eu vou querer a feijoada. A conta, por favor — o serviço está incluído?$p$),
('0d68dcaf-d9cf-58db-bf2b-0062fff66c8e'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,11,'A2',$p$writing$p$,$p$gramatica$p$,$p$descricoes$p$,$p$Describir: «ser» para siempre, «estar» para ahora$p$,$p$Como en español: «ser» para lo permanente (Ela é alta, é simpática) y «estar» para lo pasajero (Ele está cansado, está feliz hoje). El adjetivo concuerda: um homem alto, uma mulher alta, meninos altos.$p$,$p$A minha irmã é alta e simpática, mas hoje ela está cansada.$p$),
('2d6c5497-01fe-56d6-86bb-1561bbf8458b'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,12,'A2',$p$speaking$p$,$p$gramatica$p$,$p$saude_conselhos$p$,$p$«Estou com dor»: así se dice que algo duele$p$,$p$En Brasil el dolor se «tiene con»: estou com dor de cabeça / de garganta / de barriga. Para aconsejar, usa «você deveria…» (deberías) + infinitivo, o «É melhor…».$p$,$p$Estou com dor de garganta. — Você deveria beber água quente e descansar.$p$),
('e252a37f-b40e-5a99-89d7-17f0ae1b47ce'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,13,'B1',$p$writing$p$,$p$gramatica$p$,$p$imperfeito$p$,$p$«Era, brincava»: el imperfeito de la infancia$p$,$p$Para lo que hacías habitualmente de niño, usa el imperfeito: -ar → «brincava», -er/-ir → «comia», «dormia». Casi no hay irregulares: solo ser → «era», ter → «tinha», ir → «ia», vir → «vinha». «Quando eu era criança…» abre cualquier recuerdo.$p$,$p$Quando eu era criança, eu brincava na rua e comia pão de queijo todo dia.$p$),
('14809fc0-43fa-568d-8555-ba5ad6f187e5'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,14,'B1',$p$speaking$p$,$p$gramatica$p$,$p$futuro_condicional$p$,$p$«Gostaria»: pedir con elegancia$p$,$p$Para sonar cortés, el condicional (futuro do pretérito) suaviza: «gostaria» (me gustaría), «poderia» (podría), «seria» (sería). Se forma con -ia: falar → falaria, fazer → faria. Más formal que «vou querer».$p$,$p$Gostaria de reservar uma mesa. Você poderia me ajudar, por favor?$p$),
('c801cd15-a889-51bc-821d-c977cd4fed39'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,15,'B1',$p$writing$p$,$p$gramatica$p$,$p$subjuntivo$p$,$p$El subjuntivo de los deseos: «Espero que você venha»$p$,$p$Tras deseos y dudas (espero que, tomara que, talvez) el verbo va en subjuntivo: la vocal «se invierte» — falar → que fale, comer → que coma, vir → que venha, ser → que seja. Igual que en español («espero que vengas»).$p$,$p$Espero que você venha à festa. Tomara que faça sol amanhã!$p$),
('965ba6fc-c120-5015-ae2e-0061ed6fa724'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,16,'B1',$p$reading$p$,$p$gramatica$p$,$p$relativos$p$,$p$«Que, quem, onde»: unir dos ideas$p$,$p$«Que» sirve para cosas y personas (o livro que li, a moça que canta). «Quem» solo para personas tras preposición (a pessoa com quem falo). «Onde» para lugares (a cidade onde moro). «Cujo» = «cuyo» y concuerda (o autor cujas ideias…).$p$,$p$Este é o amigo com quem eu viajo e a cidade onde nós nos conhecemos.$p$),
('9c6f8121-8fb6-563e-b8b0-6c71f6243394'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,17,'B1',$p$speaking$p$,$p$vocabulario$p$,$p$problemas$p$,$p$«Deu problema»: hablar de imprevistos$p$,$p$Para imprevistos: «deu problema» (falló), «quebrou» (se rompió/averió), «não funciona». Para resolver: «vou resolver», «tem jeito?» (¿hay manera?) — muy brasileño. «Deu certo» = salió bien.$p$,$p$O carro quebrou e o celular não funciona. — Calma, tem jeito, vou resolver.$p$),
('4b286a2e-19ce-520f-adb1-b5df5e25e3a3'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,18,'B1',$p$writing$p$,$p$gramatica$p$,$p$comparativos$p$,$p$«Maior, melhor»: comparar sin rodeos$p$,$p$Para comparar: «mais… (do) que» / «menos… que». Ojo con los irregulares: bom → «melhor», ruim → «pior», grande → «maior», pequeno → «menor». El superlativo: «o melhor de todos», «a maior cidade».$p$,$p$São Paulo é maior que o Rio, mas para mim o Rio é melhor do que São Paulo.$p$)
